query:
SELECT id, userId, displayName, avatarInitials, livesRemaining, currentStreak, totalPoints, daysComplete, updatedAt FROM participants WHERE LOWER(displayName) LIKE '%nay%' OR LOWER(whatsappName) LIKE '%nay%';
SELECT dl.id, dl.participantId, p.displayName, dl.dayNumber, dl.logDate, dl.noAlcohol, dl.cleanEating, dl.exerciseDone, dl.exerciseDuration, dl.exerciseType, dl.exerciseProofUrl, dl.reflectionDone, dl.readTeachDone, dl.trackedEverything, dl.dayComplete, dl.pointsAwarded, dl.submittedAt, dl.updatedAt FROM daily_logs dl JOIN participants p ON p.id = dl.participantId WHERE LOWER(p.displayName) LIKE '%nay%' OR LOWER(p.whatsappName) LIKE '%nay%' ORDER BY dl.logDate DESC, dl.updatedAt DESC LIMIT 10;
SELECT pe.id, pe.participantId, p.displayName, pe.dailyLogId, pe.amountPence, pe.reason, pe.status, pe.createdAt FROM payment_events pe JOIN participants p ON p.id = pe.participantId WHERE LOWER(p.displayName) LIKE '%nay%' OR LOWER(p.whatsappName) LIKE '%nay%' ORDER BY pe.createdAt DESC LIMIT 10;

